targets.expr:
sum(
  rate(integrateds3_http_request_count_total{job=~"$job", instance=~"$instance", integrateds3_operation=~"$operation", http_response_status_code=~"5.."}[5m])
) or vector(0)

histogram_quantile(
  0.95,
  sum by (le) (
    rate(integrateds3_http_request_duration_milliseconds_bucket{job=~"$job", instance=~"$instance", integrateds3_operation=~"$operation"}[5m])
  )
) or vector(0)

histogram_quantile(
  0.95,
  sum by (le) (
    rate(integrateds3_storage_operation_duration_milliseconds_bucket{job=~"$job", instance=~"$instance", integrateds3_operation=~"$operation", integrateds3_provider_kind=~"$provider_kind"}[5m])
  )
) or vector(0)

count(
  max by (integrateds3_provider) (
    integrateds3_backend_health_status{job=~"$job", instance=~"$instance"} == 0
  )
) or vector(0)

histogram_quantile(
  0.95,
  sum by (le, integrateds3_provider_kind) (
    rate(integrateds3_storage_operation_duration_milliseconds_bucket{job=~"$job", instance=~"$instance", integrateds3_operation=~"$operation", integrateds3_provider_kind=~"$provider_kind"}[5m])
  )
)

histogram_quantile(
  0.95,
  sum by (le, integrateds3_replica_backend) (
    rate(integrateds3_replication_repair_duration_milliseconds_bucket{job=~"$job", instance=~"$instance", integrateds3_operation=~"$operation", integrateds3_replica_backend=~"$replica_backend"}[5m])
  )
)
